			if serviceName != "" {
				svc, err = conn.GetService(ctx, serviceName)
			} else {
				svc, err = cliutil.FindServiceByDescriptor(ctx, conn, "com.android.internal.app.IBatteryStats")
			}
			if err != nil {
				return err
			}

